|{{#invoke:cite|journal|last1=Stepan |first1=Alfred |s2cid=153861198 |title=India, Sri Lanka, and the Majoritarian Danger |journal=[[Journal of Democracy]] |volume=26 |pages=128–140 |language=en |doi=10.1353/jod.2015.0006 |date=7 January 2015}}
